// Validação HMAC-SHA256 (X-Signature) — segredo em $env.N8N_WEBHOOK_SECRET.
const crypto = require('crypto');
const secret = $env.N8N_WEBHOOK_SECRET || '';
const given  = ($input.first().json.headers || {})['x-signature'] || '';
let body = $input.first().json.body ? JSON.stringify($input.first().json.body) : '';
try {
  if ($input.first().binary && $input.first().binary.data) {
    body = Buffer.from($input.first().binary.data, 'base64').toString('utf8');
  }
} catch (e) {}
if (!secret) return [{ json: { ...$input.first().json, _signature_skipped: 'no_secret' } }];
const expected = crypto.createHmac('sha256', secret).update(body, 'utf8').digest('hex');
const ok = expected.length === given.length && crypto.timingSafeEqual(Buffer.from(expected), Buffer.from(given));
if (!ok) throw new Error('Assinatura HMAC inválida (X-Signature não confere)');
return [{ json: { ...$input.first().json, _signature_ok: true } }];

// Normaliza payload do evento `proposta.aprovada`.
const body = $input.first().json.body || $input.first().json;
const d = (body && body.data) || {};
return [{
  json: {
    cliente_nome:     d.cliente_nome     || 'Cliente',
    cliente_email:    d.cliente_email    || '',
    cliente_telefone: d.cliente_telefone || '',
    proposta_numero:  d.proposta_numero  || '',
    proposta_versao:  d.proposta_versao  || 1,
    valor_total:      d.valor_total      || 0,
    aprovada_por:     d.aprovada_por     || 'admin',
    obra_id:          d.obra_id          || null,
    portal_url:       d.portal_url       || '',
    admin_id:         body.admin_id      || null,
    occurred_at:      body.occurred_at   || null
  }
}];

